class Solution(object):
    def maxLength(self, nums):
        from math import gcd
        def lcm(a, b):
            return a * b // gcd(a, b)
        n = len(nums)
        best = 1
        for i in range(n):
            prod = 1
            cur_lcm = 1
            for j in range(i, n):
                prod *= nums[j]
                cur_lcm = lcm(cur_lcm, nums[j])
                if prod == cur_lcm:
                    best = max(best, j - i + 1)
                if prod > cur_lcm:
                    break
        return best
